import React, { useState, useEffect } from 'react';

function Home() { 
  const [list, setList] = useState([]);
  const [isAdmin, setIsAdmin] = useState(false); 
  const [form, setForm] = useState({ name: '', skill: '', price: '', email: '' });

  const fetchData = async () => {
    try {
      const res = await fetch('http://localhost:3000/api/get');
      const data = await res.json();
      setList(data);
    } catch (err) {
      console.log("Backend connection error");
    }
  };

  useEffect(() => { fetchData(); }, []);

  const handleAdminLogin = () => {
    const pass = prompt("Enter Admin Password:");
    if (pass === "admin123") { 
      setIsAdmin(true);
      alert("Admin Access Granted!");
    } else {
      alert("Wrong Password!");
    }
  };

  const deleteFreelancer = async (id) => {
    if (window.confirm("Delete karayche aahe ka?")) {
      await fetch(`http://localhost:3000/api/delete/${id}`, { method: 'DELETE' });
      fetchData(); 
    }
  };

  const handleAdd = async (e) => {
    e.preventDefault();
    await fetch('http://localhost:3000/api/add', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(form)
    });
    alert("Registered Successfully!");
    setForm({ name: '', skill: '', price: '', email: '' });
    fetchData();
  };

  return (
    <div className="home-container">
      {/* 1. प्रोफेशनल Hero Section */}
      <div className="hero-section">
        <div className="hero-content">
          <h1>Student Freelancer Marketplace</h1>
          <p>तुमच्या कौशल्याने कमवा, शिका आणि प्रगती करा!</p>
          <div className="hero-btns">
            <button className="btn-primary" onClick={() => window.scrollTo({top: 600, behavior: 'smooth'})}>Explore Talent</button>
            <button className="btn-secondary" onClick={isAdmin ? () => setIsAdmin(false) : handleAdminLogin}>
              {isAdmin ? "Logout Admin" : "Admin Login"}
            </button>
          </div>
        </div>
      </div>

      {/* 2. Main Content Area */}
      <div className="main-wrapper" style={{display: 'flex', gap: '40px', padding: '40px', maxWidth: '1200px', margin: '0 auto'}}>
        
        {/* Left Side: Form */}
        <div className="form-card-new" style={{flex: '1', background: '#fff', padding: '30px', borderRadius: '15px', boxShadow: '0 10px 25px rgba(0,0,0,0.1)', height: 'fit-content'}}>
          <h2 style={{color: '#333', marginBottom: '20px', textAlign: 'center'}}>Join Now</h2>
          <form onSubmit={handleAdd}>
            <div className="input-group">
              <label>Full Name</label>
              <input type="text" value={form.name} placeholder="Enter your name" required onChange={e => setForm({...form, name: e.target.value})} />
            </div>
            <div className="input-group">
              <label>Skill</label>
              <input type="text" value={form.skill} placeholder="Web Dev, Logo Design, etc." required onChange={e => setForm({...form, skill: e.target.value})} />
            </div>
            <div className="input-group">
              <label>Hourly Rate ($)</label>
              <input type="number" value={form.price} placeholder="Rate per hour" required onChange={e => setForm({...form, price: e.target.value})} />
            </div>
            <div className="input-group">
              <label>Email Address</label>
              <input type="email" value={form.email} placeholder="yourname@gmail.com" required onChange={e => setForm({...form, email: e.target.value})} />
            </div>
            <button type="submit" className="btn-join-new">Create Profile</button>
          </form>
        </div>

        {/* Right Side: Listing */}
        <div className="list-section" style={{flex: '2'}}>
          <h2 style={{marginBottom: '20px', color: '#2c3e50'}}>Available Talent {isAdmin && <small style={{color: 'red'}}>(Admin Mode)</small>}</h2>
          <div className="freelancer-grid-new" style={{display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(250px, 1fr))', gap: '20px'}}>
            {list.length > 0 ? list.map(f => (
              <div className="freelancer-card-new" key={f._id}>
                <div className="card-header">
                  <div className="avatar-new">{f.name.charAt(0)}</div>
                  <div className="header-text">
                    <h3>{f.name}</h3>
                    <span className="skill-tag-new">{f.skill}</span>
                  </div>
                </div>
                <div className="card-body">
                  <p><strong>Rate:</strong> ${f.price}/hr</p>
                  <p><strong>Email:</strong> {f.email}</p>
                </div>
                {isAdmin && (
                  <button className="btn-delete-new" onClick={() => deleteFreelancer(f._id)}>Delete Profile</button>
                )}
              </div>
            )) : <p>No freelancers found. Be the first to join!</p>}
          </div>
        </div>
      </div>
    </div>
  );
}

export default Home;
